## 1. Scope Extension

This addendum extends the trauma-informed intake schema (v1.0) to include a **Stability Progress Tracker**—a quantitative case-management support tool that calculates monthly Stability Scores based on client adherence to mutually established goals. This capability enables resource-constrained agencies to prioritize outreach efforts and identify clients requiring intensive support interventions.

**Design Constraint:** The tracker must operate within trauma-informed principles—scores reflect systemic barriers rather than moral failings, and data collection prioritizes client autonomy and dignity.

---

## 2. Extended Data Model

### 2.1 Core Entities

```typescript
// Stability Metric Configuration (Agency-defined weights)
interface StabilityMetricConfig {
  metricId: UUID;
  agencyId: UUID;
  metricType: 'ATTENDANCE' | 'DOCUMENT_SUBMISSION' | 'REFERRAL_FOLLOW_THROUGH' | 'CUSTOM';
  weight: number; // 0.0 - 1.0, sum of all active metrics = 1.0
  lookbackDays: number; // Default: 30
  gracePeriodHours: number; // Buffer for trauma-informed flexibility
  description: string;
  isActive: boolean;
  createdAt: Timestamp;
}

// Individual Progress Events (Immutable audit trail)
interface ProgressEvent {
  eventId: UUID;
  applicationId: UUID; // Links to IntakeApplication
  metricId: UUID;
  eventType: 'SCHEDULED' | 'COMPLETED' | 'MISSED' | 'RESCHEDULED' | 'EXCUSED';
  eventTimestamp: Timestamp;
  dueDate?: Date; // For document submissions
  completionDate?: Date;
  excusedAbsence: boolean; // Caseworker override for trauma/crisis
  excusedReason?: string; // Internal note, encrypted
  barrierFlags: BarrierType[]; // Housing, health, transport, safety
  pointsEarned: number; // Calculated at commit time
  maxPointsAvailable: number;
  caseworkerId: UUID;
  clientNotified: boolean;
}

// Monthly Aggregated Score (Materialized view)
interface StabilityScore {
  scoreId: UUID;
  applicationId: UUID;
  calculationPeriod: string; // YYYY-MM format
  totalScore: number; // 0-100 scale
  percentileRank?: number; // Relative to cohort
  metricBreakdown: MetricScore[];
  riskFlag: 'STABLE' | 'AT_RISK' | 'CRISIS' | 'NEW'; // Derived from score + barriers
  caseworkerNotes: string;
  clientViewableSummary?: string; // Trauma-informed, non-judgmental language
  calculatedAt: Timestamp;
  nextReviewDate: Date;
}

interface MetricScore {
  metricId: UUID;
  metricName: string;
  weight: number;
  rawScore: number; // 0-100
  weightedContribution: number;
  eventsCount: number;
  trend: 'IMPROVING' | 'STABLE' | 'DECLINING';
}
```

### 2.2 Database Schema (PostgreSQL)

```sql
-- Progress Events Table (Partitioned by month for performance)
CREATE TABLE progress_events (
    event_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    application_id UUID NOT NULL REFERENCES intake_applications(id),
    metric_id UUID NOT NULL REFERENCES stability_metrics(id),
    event_type VARCHAR(20) CHECK (event_type IN ('SCHEDULED', 'COMPLETED', 'MISSED', 'RESCHEDULED', 'EXCUSED')),
    event_timestamp TIMESTAMPTZ NOT NULL,
    due_date DATE,
    completion_date DATE,
    excused_absence BOOLEAN DEFAULT FALSE,
    excused_reason TEXT, -- Encrypted at application layer
    barrier_flags INTEGER[], -- Bitmask mapping to barrier types
    points_earned DECIMAL(5,2),
    max_points_available DECIMAL(5,2),
    caseworker_id UUID NOT NULL REFERENCES staff(id),
    client_notified BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMPTZ DEFAULT NOW()
) PARTITION BY RANGE (event_timestamp);

-- Stability Scores (Materialized view refreshed nightly)
